config_template.content:
Umask 026

Tuning {
    NumConnections 15
    BufSize 12288
    InputBufSize 4096
    ScriptBufSize 4096
    NumHeaders 100
    Timeout 60
    ScriptTimeout 60
    MaxUploadSize 15859712
}

PIDFile /var/run/httpd.pid
LogGMT On

Control {
    Types {
        text/html { html htm php }
        text/xml { xml }
        text/plain { txt }
        image/gif { gif }
        image/jpeg { jpg }
        text/css { css }
        application/ocstream { * }
    }
    Specials {
        Dump { /dump }
        CGI { cgi }
        Imagemap { map }
        Redirect { url }
        Internal { _int }
    }
    External {
        /sbin/atp { php txt }
        /sbin/xgi { xgi bin dcf log }
        /sbin/sgi { sgi }
    }
    IndexNames { index.html index.php }
}

Server {
    Port 80
    Virtual {
        AnyHost
        Control {
            Alias /
            Location /www
        }
    }
}
